/**
 * ---------------------------------------------------------------------------
 * 1. CasbinRule — raw Casbin policy/grouping rows stored in PostgreSQL.
 * Casbin gorm-adapter reads/writes this table directly.
 * p-type rows: ptype="p"  → policy line: sub, dom, obj, act, eft
 * g-type rows: ptype="g"  → role assignment: sub, dom, role
 * ---------------------------------------------------------------------------
 */
export type CasbinRule = {
  /**
   * @inject_tag: gorm:"primarykey;autoIncrement"
   */
  id?: string;
  /**
   * ptype: "p" = policy line, "g" = role-inheritance line
   * @inject_tag: gorm:"size:10;uniqueIndex:unique_index"
   */
  ptype?: string;
  /**
   * v0: subject  (p-line) | member (g-line)
   * @inject_tag: gorm:"size:256;uniqueIndex:unique_index"
   */
  v0?: string;
  /**
   * v1: domain   (p-line: portal:tenant) | domain (g-line: portal:tenant)
   * @inject_tag: gorm:"size:256;uniqueIndex:unique_index"
   */
  v1?: string;
  /**
   * v2: object   (p-line: svc:resource) | role (g-line: role:<name>)
   * @inject_tag: gorm:"size:256;uniqueIndex:unique_index"
   */
  v2?: string;
  /**
   * v3: action   (p-line: HTTP verb / domain action)
   * @inject_tag: gorm:"size:256;uniqueIndex:unique_index"
   */
  v3?: string;
  /**
   * v4: effect   (p-line: allow | deny)
   * @inject_tag: gorm:"size:256;uniqueIndex:unique_index"
   */
  v4?: string;
  /**
   * v5: reserved for future ABAC conditions / attribute matchers
   * @inject_tag: gorm:"size:256;uniqueIndex:unique_index"
   */
  v5?: string;
};

/**
 * ---------------------------------------------------------------------------
 * 4. PolicyRule — human-readable view of a Casbin policy line.
 * Writes sync to casbin_rules via the authz service.
 * ---------------------------------------------------------------------------
 */
export type PolicyRule = {
  policy_id: string;
  /**
   * Subject: "role:<name>" or "user:<uuid>"
   */
  subject: string;
  /**
   * Domain: "portal:tenant_id"
   */
  domain: string;
  /**
   * Object: "svc:<service>/<resource>"
   */
  object: string;
  /**
   * Action: HTTP verb or domain verb
   */
  action: string;
  effect: PolicyEffect;
  /**
   * Optional ABAC condition expression (evaluated by custom matcher)
   */
  condition?: string;
  description?: string;
  is_active: boolean;
  created_by?: string;
  created_at: string;
  updated_at: string;
  deleted_at?: string;
};

/**
 * ---------------------------------------------------------------------------
 * 5. PortalConfig — per-portal MFA and session configuration
 * ---------------------------------------------------------------------------
 */
export type PortalConfig = {
  portal_config_id: string;
  portal: Portal;
  mfa_required: boolean;
  /**
   * stored as JSONB: ["totp","sms","email"]
   */
  mfa_methods?: Array<string>;
  /**
   * Token expiry in seconds — configurable, default 900 (15 min)
   */
  access_token_ttl_seconds: number;
  refresh_token_ttl_seconds: number;
  session_ttl_seconds: number;
  idle_timeout_seconds: number;
  allow_concurrent_sessions: boolean;
  max_concurrent_sessions: number;
  updated_by?: string;
  updated_at: string;
};

