  /**
   * @inject_tag: gorm:"column:customer_id;not null"
   */
  customer_id: string;
  /**
   * @inject_tag: gorm:"column:product_id;not null"
   */
  product_id: string;
  /**
   * @inject_tag: gorm:"column:plan_id;not null"
   */
  plan_id: string;
  status: OrderStatus;
  /**
   * @inject_tag: gorm:"column:total_payable;not null"
   */
  total_payable: Money;
  /**
   * @inject_tag: gorm:"column:currency;not null"
   */
  currency: string;
  /**
   * Payment fields — populated after InitiatePayment
   * @inject_tag: gorm:"column:payment_id"
   */
  payment_id?: string;
  /**
   * @inject_tag: gorm:"column:payment_gateway_ref"
   */
  payment_gateway_ref?: string;
  /**
   * Policy fields — populated after PolicyIssued
   * @inject_tag: gorm:"column:policy_id"
   */
  policy_id?: string;
  /**
   * @inject_tag: gorm:"column:cancellation_reason"
   */
  cancellation_reason?: string;
  /**
   * @inject_tag: gorm:"column:failure_reason"
   */
  failure_reason?: string;
  /**
   * @inject_tag: gorm:"column:created_at;not null;serializer:proto_timestamp"
   */
  created_at: string;
  /**
   * @inject_tag: gorm:"column:updated_at;not null;serializer:proto_timestamp"
   */
  updated_at: string;
  /**
   * @inject_tag: gorm:"column:paid_at;serializer:proto_timestamp"
   */
  paid_at?: string;
  /**
   * @inject_tag: gorm:"column:invoice_id;index:idx_orders_invoice_id"
   */
  invoice_id?: string;
  /**
   * @inject_tag: gorm:"column:organisation_id;index:idx_orders_organisation_id"
   */
  organisation_id?: string;
  /**
   * @inject_tag: gorm:"column:idempotency_key;uniqueIndex"
   */
  idempotency_key?: string;
  /**
   * @inject_tag: gorm:"column:correlation_id"
   */
  correlation_id?: string;
  payment_status: OrderPaymentStatus;
  billing_status: OrderBillingStatus;
  fulfillment_status: OrderFulfillmentStatus;
  /**
   * @inject_tag: gorm:"column:manual_review_required;not null;default:false"
   */
  manual_review_required: boolean;
  /**
   * @inject_tag: gorm:"column:payment_due_at;serializer:proto_timestamp"
   */
  payment_due_at?: string;
  /**
   * @inject_tag: gorm:"column:coverage_start_at;serializer:proto_timestamp"
   */
  coverage_start_at?: string;
  /**
   * @inject_tag: gorm:"column:coverage_end_at;serializer:proto_timestamp"
   */
  coverage_end_at?: string;
  /**
   * @inject_tag: gorm:"column:actor_user_id"
   */
