/**
 * Session represents user authentication session (HYBRID: Server-side + JWT)
 * Maps to 'sessions' table in authn_schema
 */
export type SessionWritable = {
  /**
   * @inject_tag: gorm:"primaryKey;column:session_id;not null"
   */
  session_id?: string;
  /**
   * @inject_tag: gorm:"column:user_id;not null"
   */
  user_id?: string;
  /**
   * Session type determines authentication method (SERVER_SIDE for web, JWT for
   * mobile)
   * @inject_tag: gorm:"column:session_type;not null;serializer:proto_enum"
   */
  session_type?: SessionType;
  /**
   * Bcrypt hash of session token for server-side sessions (web portals)
   * Only populated when session_type = SERVER_SIDE
   * @inject_tag: gorm:"column:session_token_hash"
   */
  session_token_hash?: string;
  /**
   * Deterministic lookup hash (sha256 hex) of the plain session token.
   * Used to find the session row quickly, then the plain token is verified against
   * bcrypt session_token_hash.
   * Only populated when session_type = SERVER_SIDE.
   * @inject_tag: gorm:"column:session_token_lookup"
   * ========================================
   * JWT SESSION FIELDS (Mobile/API)
   * ========================================
   */
  session_token_lookup?: string;
  /**
   * JWT ID for access token (only for JWT sessions)
   * @inject_tag: gorm:"column:access_token_jti"
   */
  access_token_jti?: string;
  /**
   * JWT ID for refresh token (only for JWT sessions)
   * @inject_tag: gorm:"column:refresh_token_jti"
   */
  refresh_token_jti?: string;
  /**
   * @inject_tag: gorm:"column:access_token_expires_at;serializer:proto_timestamp"
   * gorm:"column:access_token_expires_at;serializer:proto_timestamp"
   */
  access_token_expires_at?: string;
  /**
   * @inject_tag: gorm:"column:refresh_token_expires_at;serializer:proto_timestamp"
   * gorm:"column:refresh_token_expires_at;serializer:proto_timestamp"
   */
  refresh_token_expires_at?: string;
  /**
   * Session expiry: 12 hours for SERVER_SIDE, 7 days for JWT
   * @inject_tag: gorm:"column:expires_at;not null;serializer:proto_timestamp"
   */
  expires_at?: string;
  /**
   * @inject_tag: gorm:"column:ip_address"
   */
  ip_address?: string;
  /**
   * @inject_tag: gorm:"column:user_agent"
   */
  user_agent?: string;
  /**
   * @inject_tag: gorm:"column:device_id"
   */
  device_id?: string;
  /**
   * @inject_tag: gorm:"column:device_name"
   */
  device_name?: string;
  /**
   * @inject_tag: gorm:"column:device_type;not null;serializer:proto_enum"
   */
  device_type?: AuthnDeviceType;
  /**
   * @inject_tag: gorm:"column:created_at;not null;serializer:proto_timestamp"
   */
  created_at?: string;
  /**
   * @inject_tag: gorm:"column:last_activity_at;not null;serializer:proto_timestamp"
   * null;serializer:proto_timestamp"
   */
  last_activity_at?: string;
  /**
   * @inject_tag: gorm:"column:is_active;not null"
   */
  is_active?: boolean;
  /**
   * CSRF token for server-side sessions (web portals only)
   * @inject_tag: gorm:"column:csrf_token"
   */
  csrf_token?: string;
};

